#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int dp[N][N];
        for (int i = 0; i < N; i++) {
            dp[i][i] = 0;
        }
        for (int len = 2; len <= N; len++) {
            for (int i = 0; i <= N - len; i++) {
                int j = i + len - 1;
                dp[i][j] = A[i];
                for (int k = i + 1; k <= j; k++) {
                    if (A[k] < A[i]) {
                        dp[i][j] = dp[i][j] > dp[i + 1][j] + A[k] ? dp[i + 1][j] + A[k] : dp[i][j];
                    }
                }
            }
        }
        printf("%d\n", dp[0][N - 1]);
    }
    return 0;
}

