        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int[][] dp = new int[N][N];
            for (int i = 0; i < N; i++) {
                dp[i][i] = 0;
            }
            for (int len = 2; len <= N; len++) {
                for (int i = 0; i <= N - len; i++) {
                    int j = i + len - 1;
                    dp[i][j] = A[i];
                    for (int k = i + 1; k <= j; k++) {
                        if (A[k] < A[i]) {
                            dp[i][j] = dp[i][j] > dp[i + 1][j] + A[k] ? dp[i + 1][j] + A[k] : dp[i][j];
