import sys
input = sys.stdin.readline
T = int(input())
for _ in range(T):
    N = int(input())
    A = list(map(int, input().split()))
    dp = [[0] * N for _ in range(N)]
    for i in range(N):
        dp[i][i] = 0
    for length in range(2, N + 1):
        for i in range(N - length + 1):
            j = i + length - 1
            dp[i][j] = A[i]
            for k in range(i + 1, j + 1):
                if A[k] < A[i]:
                    dp[i][j] = min(dp[i][j], dp[i + 1][j] + A[k])
    print(dp[0][N - 1])

