    const dp = Array(N).fill(0).map(() => Array(N).fill(0));
    for (let j = 0; j < N; j++) {
        dp[j][j] = 0;
    }
    for (let len = 2; len <= N; len++) {
        for (let j = 0; j <= N - len; j++) {
            const k = j + len - 1;
            dp[j][k] = A[j];
            for (let l = j + 1; l <= k; l++) {
                if (A[l] < A[j]) {
                    dp[j][k] = Math.min(dp[j][k], dp[j + 1][k] + A[l]);
